def solve(arg1: dict) -> int:
    challenge_id = arg1.get('challengeId')

    # Simulated data for reviewers and submissions
    reviewers = {
        '12345': ['reviewer1', 'reviewer2', 'reviewer3'],
        '67890': ['reviewer4']
    }

    submissions = {
        '12345': ['submission1', 'submission2', 'submission3'],
        '67890': ['submission4']
    }

    if challenge_id not in reviewers:
        return 'Error: Challenge not found'

    total_reviewers = len(reviewers[challenge_id])
    total_submissions = len(submissions[challenge_id])

    if total_reviewers == 0:
        return 0

    # Assuming each reviewer is expected to submit one review
    progress = (total_submissions / total_reviewers) * 100

    return round(progress, 2)
